PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT DISTINCT ?actor ?actorLabel ?otherSeries ?otherSeriesLabel WHERE {
  ?series wdt:P2215 wd:Q1447246 ; wdt:P31 wd:Q1525032 ; wdt:P577 ?firstAired .
  ?series wdt:P161 ?actor .
  ?otherSeries wdt:P161 ?actor ; wdt:P31 wd:Q1525032 ; wdt:P577 ?otherFirstAired .
  FILTER(?otherFirstAired > ?firstAired)
  FILTER(?otherSeries != ?series)
  OPTIONAL {
    ?actor rdfs:label ?actorLabel .
    FILTER(LANG(?actorLabel) = "en")
  }
  OPTIONAL {
    ?otherSeries rdfs:label ?otherSeriesLabel .
    FILTER(LANG(?otherSeriesLabel) = "en")
  }
}

